insert into oj.problem (id, _id, is_public, title, description, samples, run_test, hint, languages, create_time, last_update_time, time_limit, memory_limit, Stack_memory_limit, template, mode, visible, difficulty, source, submission_number, accepted_number, created_by_id, test_id)
values  (1, '1', true, '十个数排序', '<p><span style="color:#032f62;">对简单的十个数进行排序</span></p>', '[{"input": "17 627 778 388 991 589 890 608 927 660", "output": "17 388 589 608 627 660 778 890 927 991", "explanation": "无"}]', '[{"input": "17 627 778 388 991 589 890 608 927 660", "output": "17 388 589 608 627 660 778 890 927 991"}]', '<ul><li>1&lt;n&lt;100000</li><li>&lt;1x&lt;1000</li></ul>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-12 13:23:20.612021', '2025-05-05 13:27:00.000000', '{"c": "1000", "cpp": "1", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'ACM', true, '2', '无', 77, 34, 1, 1),
        (2, '2', true, '判断三角形形状', '<p>给你三角形的三条边，你能告诉我它是哪种三角形吗？<br>如果是直角三角形，请输出“good”。如果是等腰三角形，请输出“perfect”。否则，请输出“just a triangle”。<br>题目保证输入数据合法。</p>', '[{"input": "43 4 5\\n2 2 3 \\n1 4 4\\n4 6 3", "output": "good\\n<p>\\n    perfect\\n</p>\\n<p>\\n    perfect\\n</p>\\n<p>\\n    just a triangle\\n</p>", "explanation": "The first triangle is a right triangle, the second is an equilateral triangle, the third is an isosceles triangle, and the fourth is just a triangle."}]', '[{"input": "43 4 5\\n2 2 3 \\n1 4 4\\n4 6 3", "output": "good\\nperfect\\nperfect\\njust a triangle"}]', '<p>对于每组样例，输出结果，每组结果占一行</p>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-28 07:09:23.389529', '2025-05-28 07:08:00.000000', '{"c": "1000", "cpp": "1000", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'ACM', true, '1', '无', 0, 0, 1, 2),
        (3, '3', true, '水仙花数', '<p>春天是鲜花的季节，水仙花就是其中最迷人的代表，数学上有个水仙花数，他是这样定义的：<br>“水仙花数”是指一个三位数，它的各位数字的立方和等于其本身，比如：153=1^3+5^3+3^3。<br>现在要求输出所有在m和n范围内的水仙花数。</p>', '[{"input": "300 380", "output": "370 371", "explanation": "比较简单，无"}]', '[{"input": "300 380", "output": "370 371"}]', '<p>无</p>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-28 07:28:18.298602', null, '{"c": "1000", "cpp": "1000", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'ACM', true, '1', '无', 0, 0, 1, 3),
        (4, '4', true, '完全背包问题', '<p>设有n种物品，每种物品有一个重量及一个价值。但每种物品的数量是无限的，同时有一个背包，最大载重量为M，今从n种物品中选取若干件(同一种物品可以多次选取)，使其重量的和小于等于M，而价值的和为最大。</p>', '[{"input": "12 4\\n2  1\\n3  3\\n4  5\\n7  9\\n", "output": "max=15", "explanation": "无"}]', null, '<p>&nbsp;</p>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-28 09:43:31.700024', '2025-05-28 09:42:00.000000', '{"c": "1000", "cpp": "1000", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'OI', true, '3', '无', 10, 1, 1, 4),
        (5, '5', true, '十进制转八进制', '<p>用递归的方法将十进制整数n转换成八进制整数m</p>', '[{"input": "15", "output": "17", "explanation": "十五的八进制是17"}]', null, '<ul><li>使用递归的方法</li><li>1&lt;n&lt;100</li></ul>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-28 11:13:39.170980', '2025-05-28 11:12:00.000000', '{"c": "1000", "cpp": "1000", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'OI', true, '2', 'HOJ', 107, 38, 1, 5),
        (6, '6', true, '奇偶位互换', '<p>给定一个长度为偶数位的0，1字符串，请编程实现串的奇偶位互换。</p>', '[{"input": "2\\n0110\\n1100", "output": "1001\\n1100"}]', null, '<p>接下来是C组测试数据，每组数据输入均为0，1字符串，保证串长为偶数位(串长&lt;=50)</p>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-28 11:26:49.285950', '2025-05-28 11:26:00.000000', '{"c": "1000", "cpp": "1000", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'ACM', true, '2', '无', 58, 45, 1, 7),
        (7, '7', true, '求最大公约数和最小公倍数', '<p>有两个正整数，想知道它们的最大公约数和最小公倍数，你有什么办法？</p>', '[{"input": "6 8", "output": "2 24", "explanation": "6 和 8 的最大公约数是 2，最小公倍数是 24"}, {"input": "10 15", "output": "5 30", "explanation": "10 和 15 的最大公约数是 5，最小公倍数是 30"}]', null, '<ul><li>充分考虑大数据情况</li><li>0&lt;m&lt;n&lt;1000000</li></ul>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-28 11:31:56.427082', '2025-05-28 11:30:00.000000', '{"c": "1000", "cpp": "1000", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'ACM', true, '3', '', 345, 123, 1, 8),
        (8, '8', true, '删数问题', '<p>去掉任意ｓ个数字后剩下的数字按原左右次序将组成一个新的正整数。<br>编程对给定的ｎ和ｓ，寻找一种方案，使得剩下的数最小。</p>', '[{"input": "178543\\n4", "output": "13", "explanation": "无"}]', null, '<p>n&lt;=240</p>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-28 11:40:31.897530', '2025-05-28 11:39:00.000000', '{"c": "1000", "cpp": "1000", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'ACM', true, '3', '', 102, 46, 1, 9),
        (9, '9', true, '二维数组输出', '<p>输入一个整数N，输出一个N行N列的二维矩阵，矩阵中的元素用1——N*N顺序螺旋填充。</p>', '[{"input": "3", "output": "1 2 3<br>8 9 4<br>7 6 5", "explanation": "无"}, {"input": "4", "output": "1 2 3 4<br>12 13 14 5<br>11 16 15 6<br>10 9 8 7", "explanation": "无"}]', null, '<p>不要有空格</p>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-28 11:45:54.286403', '2025-05-28 11:45:00.000000', '{"c": "1000", "cpp": "1000", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'ACM', true, '2', '无', 50, 25, 1, 10),
        (10, '10', true, '数组元素的查找', '<p>给你m个整数，查找其中有无值为n的数，有则输出该数第一次出现的位置,没有则输出-1。</p>', '[{"input": "4\\n1 2 3 3\\n3 2 1 3\\n3 2 3 1\\n3 3 1 2", "output": "3", "explanation": "无"}]', null, '<p>无</p>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-28 11:51:32.567716', '2025-05-28 11:50:00.000000', '{"c": "1000", "cpp": "1000", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'ACM', true, '3', '无', 68, 56, 1, 12),
        (11, '11', true, '第K小整数', '<p>现有n个正整数，n&lt;=10000,要求出这n个正整数的第k个最小整数（相同大小的整数只计算一次），k&lt;=1000,正整数均小于30000</p>', '[{"input": "10 3<br>1 3 3 7 2 5 1 2 4 6", "output": "3", "explanation": "无"}]', null, '<p>k&lt;=1000,正整数均小于30000</p>', '{"c": "c", "cpp": "cpp", "java": "java", "golang": "golang", "python": "python"}', '2025-05-28 11:56:58.275485', '2025-05-28 11:56:00.000000', '{"c": "1000", "cpp": "1000", "java": "1000", "golang": "1000", "python": "1000"}', '{"c": "100", "cpp": "10", "java": "1000", "golang": "1000", "python": "1000"}', null, null, 'ACM', true, '3', '无', 79, 56, 1, 13);